static bool controller_has_timed_out(const controller_t *controller, uint32_t now_ms)
{
    if (controller == 0 || !controller->has_valid_sensor) {
        return false;
    }

    return (uint32_t)(now_ms - controller->last_valid_sensor_ms) > CONTROLLER_SENSOR_TIMEOUT_MS;
