from __future__ import annotations

import subprocess
import textwrap
import unittest
from pathlib import Path

from bench_public import FirmwareSession, self_test_artifact_dir

WORKSPACE_ROOT = Path(__file__).resolve().parents[1]
CONTROLLER_DIR = WORKSPACE_ROOT / "components" / "controller"
CONTROLLER_INCLUDE = CONTROLLER_DIR / "include"
CONTROLLER_SOURCE = CONTROLLER_DIR / "controller.c"

C_TEMPLATE = textwrap.dedent(
    r"""
    #include <stdbool.h>
    #include <stdint.h>
    #include <stdio.h>
    #include <string.h>

    #include "controller.h"

    #define CHECK(expr) \
        do { \
            if (!(expr)) { \
                printf("CHECK_FAIL:%s:%d:%s\n", __FILE__, __LINE__, #expr); \
                return 1; \
            } \
        } while (0)

    int main(void)
    {
    {body}
        puts("OK");
        return 0;
    }
    """
)


def _compile_and_run(label: str, body: str) -> str:
    artifact_dir = self_test_artifact_dir(label)
    source_path = artifact_dir / "scenario.c"
    binary_path = artifact_dir / "scenario"
    source_path.write_text(
        C_TEMPLATE.format(body=textwrap.indent(textwrap.dedent(body).strip("\n"), "    ")),
        encoding="utf-8",
    )
    completed = subprocess.run(
        [
            "gcc",
            "-std=c99",
            "-Wall",
            "-Wextra",
            "-I",
            str(CONTROLLER_INCLUDE),
            str(source_path),
            str(CONTROLLER_SOURCE),
            "-o",
            str(binary_path),
        ],
        cwd=WORKSPACE_ROOT,
        capture_output=True,
        text=True,
        check=False,
    )
    if completed.returncode != 0:
        raise AssertionError(
            f"controller harness compilation failed for {label}\nSTDOUT:\n{completed.stdout}\nSTDERR:\n{completed.stderr}"
        )

    completed = subprocess.run(
        [str(binary_path)],
        cwd=WORKSPACE_ROOT,
        capture_output=True,
        text=True,
        check=False,
    )
    if completed.returncode != 0:
        raise AssertionError(
            f"controller harness failed for {label}\nSTDOUT:\n{completed.stdout}\nSTDERR:\n{completed.stderr}"
        )
    return completed.stdout.strip()


class ControllerPolicyTests(unittest.TestCase):
    def test_boot_leaves_pump_off_before_valid_input(self) -> None:
        output = _compile_and_run(
            "boot_off",
            """
            controller_t controller = {0};
            controller_init(&controller);

            controller_output_t out = controller_step(
                &controller,
                (controller_input_t){
                    .kind = CONTROLLER_INPUT_NONE,
                    .level = 0,
                    .now_ms = 0U,
                }
            );

            CHECK(out.pump_on == false);
            CHECK(out.state == CONTROLLER_STATE_SAFE_OFF);
            CHECK(out.changed == false);
            CHECK(out.timed_out == false);
            CHECK(strcmp(out.state_name, "STATE SAFE_OFF") == 0);
            """,
        )
        self.assertEqual(output, "OK")

    def test_low_level_turns_pump_on(self) -> None:
        output = _compile_and_run(
            "low_on",
            """
            controller_t controller = {0};
            controller_init(&controller);

            controller_output_t out = controller_step(
                &controller,
                (controller_input_t){
                    .kind = CONTROLLER_INPUT_LEVEL,
                    .level = 20,
                    .now_ms = 10U,
                }
            );

            CHECK(out.pump_on == true);
            CHECK(out.state == CONTROLLER_STATE_PUMPING);
            CHECK(out.changed == true);
            CHECK(out.timed_out == false);
            CHECK(strcmp(out.state_name, "STATE PUMPING") == 0);
            """,
        )
        self.assertEqual(output, "OK")

    def test_high_level_turns_pump_off(self) -> None:
        output = _compile_and_run(
            "high_off",
            """
            controller_t controller = {0};
            controller_init(&controller);

            (void)controller_step(
                &controller,
                (controller_input_t){
                    .kind = CONTROLLER_INPUT_LEVEL,
                    .level = 20,
                    .now_ms = 10U,
                }
            );

            controller_output_t out = controller_step(
                &controller,
                (controller_input_t){
                    .kind = CONTROLLER_INPUT_LEVEL,
                    .level = 85,
                    .now_ms = 20U,
                }
            );

            CHECK(out.pump_on == false);
            CHECK(out.state == CONTROLLER_STATE_SAFE_OFF);
            CHECK(out.changed == true);
            CHECK(out.timed_out == false);
            CHECK(strcmp(out.state_name, "STATE SAFE_OFF") == 0);
            """,
        )
        self.assertEqual(output, "OK")

    def test_mid_band_preserves_previous_safe_output(self) -> None:
        output = _compile_and_run(
            "mid_band_hold",
            """
            controller_t controller = {0};
            controller_init(&controller);

            (void)controller_step(
                &controller,
                (controller_input_t){
                    .kind = CONTROLLER_INPUT_LEVEL,
                    .level = 20,
                    .now_ms = 10U,
                }
            );

            controller_output_t out = controller_step(
                &controller,
                (controller_input_t){
                    .kind = CONTROLLER_INPUT_LEVEL,
                    .level = 50,
                    .now_ms = 20U,
                }
            );

            CHECK(out.pump_on == true);
            CHECK(out.state == CONTROLLER_STATE_HOLDING);
            CHECK(out.changed == true);
            CHECK(out.timed_out == false);
            CHECK(strcmp(out.state_name, "STATE HOLDING") == 0);
            """,
        )
        self.assertEqual(output, "OK")

    def test_short_idle_steps_do_not_timeout_immediately(self) -> None:
        output = _compile_and_run(
            "idle_no_timeout",
            """
            controller_t controller = {0};
            controller_init(&controller);

            (void)controller_step(
                &controller,
                (controller_input_t){
                    .kind = CONTROLLER_INPUT_LEVEL,
                    .level = 20,
                    .now_ms = 10U,
                }
            );

            controller_output_t out = controller_step(
                &controller,
                (controller_input_t){
                    .kind = CONTROLLER_INPUT_NONE,
                    .level = 0,
                    .now_ms = 500U,
                }
            );

            CHECK(out.pump_on == true);
            CHECK(out.state == CONTROLLER_STATE_PUMPING);
            CHECK(out.changed == false);
            CHECK(out.timed_out == false);
            """,
        )
        self.assertEqual(output, "OK")

    def test_malformed_input_forces_pump_off(self) -> None:
        output = _compile_and_run(
            "malformed_off",
            """
            controller_t controller = {0};
            controller_init(&controller);

            (void)controller_step(
                &controller,
                (controller_input_t){
                    .kind = CONTROLLER_INPUT_LEVEL,
                    .level = 20,
                    .now_ms = 10U,
                }
            );

            controller_output_t out = controller_step(
                &controller,
                (controller_input_t){
                    .kind = CONTROLLER_INPUT_INVALID_LEVEL,
                    .level = 999,
                    .now_ms = 20U,
                }
            );

            CHECK(out.pump_on == false);
            CHECK(out.state == CONTROLLER_STATE_SAFE_OFF);
            CHECK(out.changed == true);
            CHECK(out.timed_out == false);
            CHECK(strcmp(out.state_name, "STATE SAFE_OFF") == 0);
            """,
        )
        self.assertEqual(output, "OK")

    def test_timeout_after_more_than_1000ms_forces_pump_off(self) -> None:
        output = _compile_and_run(
            "timeout_off",
            """
            controller_t controller = {0};
            controller_init(&controller);

            (void)controller_step(
                &controller,
                (controller_input_t){
                    .kind = CONTROLLER_INPUT_LEVEL,
                    .level = 20,
                    .now_ms = 10U,
                }
            );

            controller_output_t out = controller_step(
                &controller,
                (controller_input_t){
                    .kind = CONTROLLER_INPUT_NONE,
                    .level = 0,
                    .now_ms = 1011U,
                }
            );

            CHECK(out.pump_on == false);
            CHECK(out.state == CONTROLLER_STATE_SAFE_OFF);
            CHECK(out.changed == true);
            CHECK(out.timed_out == true);
            CHECK(strcmp(out.state_name, "STATE SAFE_OFF") == 0);
            """,
        )
        self.assertEqual(output, "OK")


class FirmwareUartProbeTests(unittest.TestCase):
    def test_nominal_low_to_high_sequence_via_uart(self) -> None:
        artifact_dir = self_test_artifact_dir("uart_nominal")
        with FirmwareSession(artifact_dir=artifact_dir) as session:
            boot_lines = session.wait_for_boot()
            self.assertTrue(boot_lines)

            session.send_line("SENSE LEVEL 20")
            lines = session.read_until(lambda line: line == "ACT PUMP ON", timeout_s=2.0)
            self.assertIn("ACT PUMP ON", lines)

            session.send_line("SENSE LEVEL 85")
            lines = session.read_until(lambda line: line == "ACT PUMP OFF", timeout_s=2.0)
            self.assertIn("ACT PUMP OFF", lines)

            transcript = session.read_lines(timeout_s=0.2)
            self.assertNotIn("FAULT SENSOR_TIMEOUT", transcript)

